// transactions.js - Minified transactions module
let currentTransactions=[];
async function fetchTransactions(){try{const response=await fetchWithAuth(`${CONFIG.API_BASE_URL}${CONFIG.API_ENDPOINTS.TRANSACTIONS}`,{method:'GET'});if(response.ok){const transactions=await response.json();currentTransactions=Array.isArray(transactions)?transactions:[];displayTransactions(currentTransactions);return currentTransactions;}else{console.error('Failed to fetch transactions:',response.status);return[];}}catch(error){console.error('Error fetching transactions:',error);return[];}}
async function createTransaction(transactionData){try{const response=await fetchWithAuth(`${CONFIG.API_BASE_URL}${CONFIG.API_ENDPOINTS.TRANSACTIONS}`,{method:'POST',body:JSON.stringify(transactionData)});if(response.ok){const newTransaction=await response.json();showToast('Transaction recorded successfully!','success');await fetchTransactions();await updateWalletBalance();return newTransaction;}else{showToast('Failed to create transaction','error');return null;}}catch(error){console.error('Error creating transaction:',error);showToast('Network error','error');return null;}}
async function updateTransaction(transactionId,transactionData){try{const response=await fetchWithAuth(`${CONFIG.API_BASE_URL}${CONFIG.API_ENDPOINTS.TRANSACTIONS}${transactionId}/`,{method:'PUT',body:JSON.stringify(transactionData)});if(response.ok){const updatedTransaction=await response.json();showToast('Transaction updated successfully!','success');await fetchTransactions();return updatedTransaction;}else{showToast('Failed to update transaction','error');return null;}}catch(error){console.error('Error updating transaction:',error);showToast('Network error','error');return null;}}
async function deleteTransaction(transactionId){if(!confirm('Are you sure you want to delete this transaction?'))return;try{const response=await fetchWithAuth(`${CONFIG.API_BASE_URL}${CONFIG.API_ENDPOINTS.TRANSACTIONS}${transactionId}/`,{method:'DELETE'});if(response.ok){showToast('Transaction deleted successfully!','success');await fetchTransactions();await updateWalletBalance();return true;}else{showToast('Failed to delete transaction','error');return false;}}catch(error){console.error('Error deleting transaction:',error);showToast('Network error','error');return false;}}
function displayTransactions(transactions){const container=document.getElementById('transactionsList');if(!container)return;if(!transactions||transactions.length===0){container.innerHTML='<p>No transactions recorded yet.</p>';return;}
const searchTerm=document.getElementById('searchTransactions')?.value.toLowerCase()||'';const categoryFilter=document.getElementById('categoryFilter')?.value||'all';const dateFilter=document.getElementById('dateFilter')?.value||'all';
let filteredTransactions=transactions.filter(transaction=>{const matchesSearch=transaction.description.toLowerCase().includes(searchTerm)||transaction.category.toLowerCase().includes(searchTerm);const matchesCategory=categoryFilter==='all'||transaction.category===categoryFilter;const matchesDate=filterByDate(transaction,dateFilter);return matchesSearch&&matchesCategory&&matchesDate;});
container.innerHTML=filteredTransactions.map(transaction=>`
<div class="transaction-item">
<div class="transaction-icon">${getCategoryIcon(transaction.category)}</div>
<div class="transaction-details">
<div class="transaction-description">${transaction.description}</div>
<div class="transaction-meta">
<span class="transaction-category">${transaction.category}</span>
<span class="transaction-date">${formatDate(transaction.date)}</span>
</div>
</div>
<div class="transaction-amount ${transaction.amount>=0?'amount-positive':'amount-negative'}">
${transaction.amount>=0?'+':'-'}$${Math.abs(transaction.amount).toFixed(2)}
</div>
<div class="transaction-actions">
<button onclick="editTransaction(${transaction.id})" class="btn btn-sm btn-secondary">Edit</button>
<button onclick="deleteTransaction(${transaction.id})" class="btn btn-sm btn-danger">Delete</button>
</div>
</div>
`).join('');}
function filterByDate(transaction,dateFilter){if(dateFilter==='all')return true;const transactionDate=new Date(transaction.date);const today=new Date();switch(dateFilter){case'today':return transactionDate.toDateString()===today.toDateString();case'week':const weekAgo=new Date(today.getTime()-7*24*60*60*1000);return transactionDate>=weekAgo;case'month':const monthAgo=new Date(today.getTime()-30*24*60*60*1000);return transactionDate>=monthAgo;case'year':const yearAgo=new Date(today.getTime()-365*24*60*60*1000);return transactionDate>=yearAgo;default:return true;}}
function getCategoryIcon(category){const icons={'Food':'🍔','Transport':'🚗','Shopping':'🛍️','Entertainment':'🎮','Utilities':'💡','Healthcare':'🏥','Income':'💰','Transfer':'💸','Savings':'🏦'};return icons[category]||'💰';}
function formatDate(dateString){const date=new Date(dateString);return date.toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'});}
function editTransaction(transactionId){const transaction=currentTransactions.find(t=>t.id===transactionId);if(!transaction)return;const form=document.getElementById('transactionForm');if(form){document.getElementById('transactionId').value=transaction.id;document.getElementById('description').value=transaction.description;document.getElementById('amount').value=Math.abs(transaction.amount);document.getElementById('category').value=transaction.category;document.getElementById('date').value=transaction.date;document.getElementById('type').value=transaction.amount>=0?'income':'expense';document.querySelector('#transactionForm button[type="submit"]').textContent='Update Transaction';}}
function resetTransactionForm(){const form=document.getElementById('transactionForm');if(form){form.reset();document.getElementById('transactionId').value='';document.querySelector('#transactionForm button[type="submit"]').textContent='Add Transaction';}}
if(document.getElementById('transactionForm')){document.getElementById('transactionForm').addEventListener('submit',async function(e){e.preventDefault();const transactionId=document.getElementById('transactionId').value;const amount=parseFloat(document.getElementById('amount').value);const type=document.getElementById('type').value;const transactionData={description:document.getElementById('description').value,amount:type==='expense'?-amount:amount,category:document.getElementById('category').value,date:document.getElementById('date').value};if(transactionId){await updateTransaction(transactionId,transactionData);}else{await createTransaction(transactionData);}});}
if(document.getElementById('searchTransactions')){document.getElementById('searchTransactions').addEventListener('input',()=>{displayTransactions(currentTransactions);});}
if(document.getElementById('categoryFilter')){document.getElementById('categoryFilter').addEventListener('change',()=>{displayTransactions(currentTransactions);});}
if(document.getElementById('dateFilter')){document.getElementById('dateFilter').addEventListener('change',()=>{displayTransactions(currentTransactions);});}
if(window.location.pathname.includes('transactions.html')){document.addEventListener('DOMContentLoaded',fetchTransactions);}
